namespace sv_84c728fccc734ddc8a662c85e59effce.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// Interactive components subscribe to OnThemeChanged to react to updates.
/// </summary>
public sealed class ThemeService
{
    private Theme _theme = Theme.System;
    private string _accentColor = "#0d6efd";

    public Theme Theme => _theme;
    public string AccentColor => _accentColor;

    public event Action? OnThemeChanged;

    public void SetTheme(Theme theme)
    {
        if (_theme == theme) return;
        _theme = theme;
        OnThemeChanged?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (_accentColor == color) return;
        _accentColor = color;
        OnThemeChanged?.Invoke();
    }

    public void SetAll(Theme theme, string accentColor)
    {
        bool changed = _theme != theme || _accentColor != accentColor;
        _theme = theme;
        _accentColor = accentColor;
        if (changed) OnThemeChanged?.Invoke();
    }
}

@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<span class="theme-indicator" title="Current theme">
    @GetThemeIcon() <span style="color:@ThemeService.AccentColor;">@ThemeService.Theme</span>
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetThemeIcon() => ThemeService.Theme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        _ => "💻"
    };

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select" style="max-width:200px"
            value="@ThemeService.Theme"
            @onchange="OnThemeSelected">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@ThemeService.AccentColor"
           @onchange="OnColorChanged" />
</div>

<p>
    Current: <strong style="color:@ThemeService.AccentColor;">@ThemeService.Theme</strong>
    / Accent: <span style="color:@ThemeService.AccentColor;">@ThemeService.AccentColor</span>
</p>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void OnThemeSelected(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            ThemeService.SetTheme(theme);
        }
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
        ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

